@Target(AnnotationTarget.CLASS, AnnotationTarget.FUNCTION)
@Retention(AnnotationRetention.RUNTIME)
annotation class Author(val name: String, val date: String = "unknown")

@Author("Ibrahim", "2026")
class SampleProject {
    @Author("Alice")
    fun feature() {
        println("Feature implementation")
    }
}

fun main() {
    val annotation = SampleProject::class.annotations
        .filterIsInstance<Author>()
        .firstOrNull()
    println("Author: ${annotation?.name}")
}
